<?php declare(strict_types=1); namespace Database\Factories\Electronics; use App\Domains\Electronics\Models\Electronics; use Illuminate\Database\Eloquent\Factories\Factory; final class ElectronicsFactory extends Factory { protected $model = Electronics::class; public function definition(): array { return ['name' => $this->faker->words(3, true), 'sku' => strtoupper('ELEC-' . $this->faker->bothify('####')), 'category' => $this->faker->randomElement(['smartphone', 'laptop', 'tablet', 'headphones', 'monitor', 'keyboard']), 'brand' => $this->faker->randomElement(['Apple', 'Samsung', 'Sony', 'LG', 'Dell', 'Asus']), 'price' => $this->faker->numberBetween(100000, 1000000), 'current_stock' => $this->faker->numberBetween(10, 100), 'warranty_months' => 12, 'rating' => $this->faker->randomFloat(1, 3.5, 5), 'review_count' => $this->faker->numberBetween(50, 500), 'status' => 'active', 'correlation_id' => \Illuminate\Support\Str::uuid()->toString(), 'tags' => ['electronics', 'tech'], 'meta' => []]; } public function premium(): self { return $this->state(['price' => $this->faker->numberBetween(500000, 1000000), 'warranty_months' => 24]); } public function budget(): self { return $this->state(['price' => $this->faker->numberBetween(100000, 250000)]); } }
